# ── Chargement données ─────────────────────────────────────────────────────────
@st.cache_data
def load_data():
    inspecteurs = pd.DataFrame(json.loads(CHARGE_JSON))
    missions = pd.DataFrame(json.loads(MISSIONS_JSON))
    conges = pd.DataFrame(json.loads(CONGES_JSON))
    # Convertir dates congés
    for col in ["Date_Debut", "Date_Fin"]:
        if col in conges.columns:
            conges[col] = pd.to_datetime(conges[col], unit="ms", errors="coerce").dt.strftime("%d/%m/%Y")
    return inspecteurs, missions, conges

inspecteurs_df, missions_df, conges_df = load_data()
VALID_INITIALES = set(inspecteurs_df["Initiale"].dropna().str.strip().str.upper().tolist())

# ── Session state ──────────────────────────────────────────────────────────────
if "logged_in" not in st.session_state:
    st.session_state.logged_in = False
if "initiale" not in st.session_state:
    st.session_state.initiale = ""

# ── Helpers ────────────────────────────────────────────────────────────────────
def get_missions_inspecteur(init):
    if missions_df.empty:
        return pd.DataFrame()
    rows = []
    for _, row in missions_df.iterrows():
        role_found = None
        for col, role in [("IP","Principal"),("Co1","Co-inspecteur"),("Co2","Co-inspecteur"),("Co3","Co-inspecteur")]:
            if col in row and str(row[col]).strip().upper() == init:
                role_found = role
                break
        if role_found is None and "Reserve" in row and str(row["Reserve"]).strip().upper() == init:
            role_found = "Réserve/Urgence"
        if role_found:
            r = row.to_dict()
            r["Mon_Role"] = role_found
            rows.append(r)
    return pd.DataFrame(rows)

def get_conges_inspecteur(init):
    if conges_df.empty:
        return pd.DataFrame()
    return conges_df[conges_df["Initiale"].str.strip().str.upper() == init].copy()

def get_charge_inspecteur(init):
    row = inspecteurs_df[inspecteurs_df["Initiale"].str.strip().str.upper() == init]
    return row.iloc[0] if not row.empty else None

def couleur_role(role):
    if role == "Principal": return "role-principal"
    if role == "Co-inspecteur": return "role-co"
    return "role-reserve"

