def page_login():
    col_l, col_c, col_r = st.columns([1, 1.2, 1])
    with col_c:
        st.markdown("""
        <div style="background:white;border-radius:16px;padding:2.5rem;
                    box-shadow:0 8px 32px rgba(0,51,102,0.15);border-top:5px solid #003366;
                    margin-top:60px;">
            <h2 style="color:#003366;text-align:center;margin-bottom:0.3rem;">🏥 ABMed</h2>
            <p style="color:#666;text-align:center;font-size:0.9rem;margin-bottom:1.5rem;">
                Agence Béninoise du Médicament<br>Plateforme de programmation des inspections 2026
            </p>
        </div>
        """, unsafe_allow_html=True)
        st.markdown("#### Connexion Inspecteur")
        initiale_input = st.text_input(
            "Vos initiales", placeholder="Ex : JA, IG, SH...",
            max_chars=4, label_visibility="collapsed"
        ).strip().upper()
        if st.button("🔐 Accéder", use_container_width=True, type="primary"):
            if initiale_input in VALID_INITIALES:
                st.session_state.logged_in = True
                st.session_state.initiale = initiale_input
                st.rerun()
            else:
                st.error("Initiales non reconnues. Vérifiez et réessayez.")
        st.caption(f"**{len(VALID_INITIALES)} inspecteurs enregistrés** | Données 2026")

